'use client'
import { useControllableSignal, useSignals } from '@cascivo/core'
import styles from './filter.module.css'

export type FilterVariant = 'pill' | 'outline'

export interface FilterOption {
  label: string
  value: string
}

export interface FilterProps {
  options: FilterOption[]
  value?: string[]
  defaultValue?: string[]
  /** Called with the selected values whenever the selection changes. */
  onValueChange?: (selected: string[]) => void
  /** @deprecated Use `onValueChange` — it receives the same `string[]`. */
  onChange?: (selected: string[]) => void
  multi?: boolean
  variant?: FilterVariant
  'aria-label'?: string
  className?: string
}

export function Filter({
  options,
  value,
  defaultValue = [],
  onValueChange,
  onChange,
  multi = false,
  variant = 'pill',
  className,
  ...aria
}: FilterProps) {
  useSignals()
  const [selected, setSelected] = useControllableSignal<string[]>({
    value,
    defaultValue,
    onChange: onValueChange ?? onChange,
  })

  function toggle(val: string) {
    const current = selected.value
    let next: string[]
    if (multi) {
      next = current.includes(val) ? current.filter((v) => v !== val) : [...current, val]
    } else {
      next = current.includes(val) ? [] : [val]
    }
    setSelected(next)
  }

  return (
    <div
      role="group"
      className={[styles['filter'], className].filter(Boolean).join(' ')}
      data-variant={variant}
      {...aria}
    >
      {options.map((opt) => (
        <button
          key={opt.value}
          type="button"
          className={styles['item']}
          data-selected={selected.value.includes(opt.value) || undefined}
          onClick={() => toggle(opt.value)}
          aria-pressed={selected.value.includes(opt.value)}
        >
          {opt.label}
        </button>
      ))}
    </div>
  )
}

@layer cascivo.component {
  .filter {
    display: flex;
    flex-wrap: wrap;
    gap: 0.375rem;
  }

  .item {
    display: inline-flex;
    align-items: center;
    padding-block: 0.25rem;
    padding-inline: 0.75rem;
    border-radius: var(--cascivo-radius-full);
    border: 1px solid var(--cascivo-border-default);
    background-color: transparent;
    color: var(--cascivo-color-text-subtle);
    font-size: 0.875rem;
    cursor: pointer;
    transition:
      background-color 100ms var(--cascivo-ease-out),
      color 100ms var(--cascivo-ease-out),
      border-color 100ms var(--cascivo-ease-out);
  }

  .item:hover {
    background-color: var(--cascivo-color-active-bg);
    color: var(--cascivo-color-text);
  }

  .item[data-selected] {
    background-color: var(--cascivo-color-accent);
    border-color: var(--cascivo-color-accent);
    color: var(--cascivo-color-accent-content);
  }

  .item:focus-visible {
    outline: var(--cascivo-ring-width) solid var(--cascivo-ring-color);
    outline-offset: 2px;
  }

  .filter[data-variant='outline'] .item[data-selected] {
    background-color: transparent;
    border-color: var(--cascivo-color-accent);
    color: var(--cascivo-color-accent);
  }
}
